parameters.text:
=Analyze this resume for the role:
{{ $('Receive Resume PDF').item.json.body.job_role || 'General' }}

Resume Text:
{{ $json.text }}

parameters.jsCode:
const rawInput = $input.item.json.output;

// Strip markdown code fences (```json ... ```)
const cleaned = rawInput
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```\s*$/i, '')
  .trim();

try {
  const parsed = JSON.parse(cleaned);

  return [{
    json: {
      ats_score: typeof parsed.ats_score === 'number' 
        ? parsed.ats_score 
        : parseInt(parsed.ats_score) || null,
      best_suited_role: parsed.best_suited_role || "",
      missing_skills: Array.isArray(parsed.missing_skills) 
        ? parsed.missing_skills 
        : [],
      improvement_suggestions: Array.isArray(parsed.improvement_suggestions) 
        ? parsed.improvement_suggestions 
        : [],
      summary: parsed.summary || ""
    }
  }];

} catch (e) {
  return [{
    json: {
      ats_score: null,
      best_suited_role: "",
      missing_skills: [],
      improvement_suggestions: [],
      summary: "",
      error: "Failed to parse AI response",
      raw: rawInput
    }
  }];
}
